const lead = $input.first().json.body;

const prompt = `You are a senior AI automation consultant at Haze Tech Solutions. A potential client has submitted an intake form. Analyze their business and create a detailed automation plan.

CLIENT INFORMATION:
- Name: ${lead.name || 'N/A'}
- Business: ${lead.business_name || 'N/A'}
- Website: ${lead.website || 'N/A'}
- Industry: ${lead.industry || 'N/A'}
- Goals: ${lead.goals || 'N/A'}
- Repetitive Tasks: ${lead.repetitive_task || 'N/A'}
- Payment Process: ${lead.payment_process || 'N/A'}
- Vendor/Employee Payment: ${lead.vendor_process || 'N/A'}
- Additional Info: ${lead.message || 'N/A'}

Create a comprehensive automation plan with:

1. EXECUTIVE SUMMARY (2-3 sentences about what we can do for them)

2. RECOMMENDED WORKFLOWS (list 3-6 specific n8n workflows we can build):
   For each workflow:
   - Workflow Name
   - Problem it Solves
   - How it Works (step by step)
   - Tools/Integrations Needed (e.g. Gmail, Slack, QuickBooks, CRM)
   - Estimated Time Saved per Week

3. QUICK WINS (1-2 automations we can deploy in week 1)

4. ESTIMATED ROI
   - Hours saved per month
   - Estimated cost savings
   - Payback period

5. IMPLEMENTATION TIMELINE
   - Phase 1 (Week 1-2): Quick wins
   - Phase 2 (Week 3-4): Core automations
   - Phase 3 (Month 2): Advanced integrations

6. RECOMMENDED PACKAGE & PRICING TIER

Be specific and practical. Reference actual tools and integrations. Make it actionable.`;

return [{ json: { prompt, leadId: lead.lead_id || null } }];

